sql:
SELECT project_name
FROM projects
ORDER BY project_name;

SELECT project_name
FROM projects
WHERE project_id = 1;

SELECT combination_name
  FROM flavor_combinations
  WHERE approved = 1;

SELECT COUNT(*) AS session_count
FROM test_sessions
WHERE conducted_by = 'John Doe';

SELECT combination_name, description
FROM flavor_combinations
WHERE approved = 1;

SELECT session_date
FROM test_sessions
ORDER BY session_date ASC;

external_knowledge:
- 'top-performing flavor combinations' refers to the combinations with the highest average scores;
- 'graduated with honors' means the combinations have been approved for further testing (i.e., ts.approved = 1);
- 'crème de la crème' refers to the top 3 ranked combinations.

sql:
